record.field:
POST /api/v2/createInvoice
Headers: Authorization: Bearer {token}
Body: {inv_series, inv_date, buyer_name, buyer_tax, items: [{name, qty, price, vat}]}
Response: {invoiceNo, pdf_url, status}

POST /api/v2/signInvoice
Body: {invoiceNo, signType: "HSM"|"TOKEN"}
Response: {signed_pdf_url, sign_date, signer_name}
